@Test(expected = IllegalArgumentException.class)
public void testHeaderDuplicateNonEmpty() throws Exception {
    final Reader in = new StringReader("a,b,a\n1,2,3");
    CSVFormat.DEFAULT.withHeader().parse(in).iterator();
}

@Test(expected = IllegalArgumentException.class)
public void testHeaderDuplicateEmptyWithIgnoreFalse() throws Exception {
    final Reader in = new StringReader("a,,c,,d\n1,2,3,4,5");
    CSVFormat.DEFAULT.withHeader().withIgnoreEmptyHeaders(false).parse(in).iterator();
}

@Test
public void testHeaderMixedEmptyNonEmpty() throws Exception {
    final Reader in = new StringReader("a,,b,,c\n1,2,3,4,5");
    CSVParser parser = CSVFormat.DEFAULT.withHeader().withIgnoreEmptyHeaders(true).parse(in);
    Map<String, Integer> headerMap = parser.getHeaderMap();
    assertEquals(3, headerMap.size());
    assertTrue(headerMap.containsKey("a"));
    assertTrue(headerMap.containsKey("b"));
    assertTrue(headerMap.containsKey("c"));
}
